
-- Create chatbot FAQs table
CREATE TABLE public.chatbot_faqs (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  question_en text NOT NULL,
  answer_en text NOT NULL,
  question_ar text NOT NULL,
  answer_ar text NOT NULL,
  category_en text DEFAULT 'General',
  category_ar text DEFAULT 'عام',
  display_order integer DEFAULT 0,
  is_active boolean DEFAULT true,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.chatbot_faqs ENABLE ROW LEVEL SECURITY;

-- Everyone can read active FAQs
CREATE POLICY "FAQs are viewable by everyone" ON public.chatbot_faqs
  FOR SELECT USING (is_active = true);

-- Admins can manage FAQs
CREATE POLICY "Admins can manage FAQs" ON public.chatbot_faqs
  FOR ALL USING (has_role(auth.uid(), 'admin'::app_role));

