INSERT INTO public.chatbot_faqs (question_en, answer_en, question_ar, answer_ar, category_en, category_ar, display_order) VALUES
('What products does Nama Steel offer?', 'Nama Steel offers a wide range of steel products including steel bars, sheets, pipes, structural steel, and custom fabrication services.', 'ما هي المنتجات التي تقدمها شركة نما للصلب؟', 'تقدم شركة نما للصلب مجموعة واسعة من منتجات الصلب بما في ذلك قضبان الصلب والألواح والأنابيب والصلب الهيكلي وخدمات التصنيع المخصصة.', 'Products', 'المنتجات', 1),
('How can I place an order?', 'You can place an order through our website by browsing products, adding them to your cart, and completing the checkout process.', 'كيف يمكنني تقديم طلب؟', 'يمكنك تقديم طلب من خلال موقعنا الإلكتروني عبر تصفح المنتجات وإضافتها إلى سلة التسوق وإكمال عملية الدفع.', 'Orders', 'الطلبات', 2),
('What are your delivery areas?', 'We deliver across Saudi Arabia. Delivery times and costs vary by location.', 'ما هي مناطق التوصيل الخاصة بكم؟', 'نقوم بالتوصيل في جميع أنحاء المملكة العربية السعودية. تختلف أوقات وتكاليف التوصيل حسب الموقع.', 'Shipping', 'الشحن', 3),
('What are the payment methods available?', 'We accept cash on delivery, bank transfers, and online payments.', 'ما هي طرق الدفع المتاحة؟', 'نقبل الدفع عند الاستلام والتحويلات البنكية والدفع الإلكتروني.', 'Payment', 'الدفع', 4),
('How long does delivery take?', 'Delivery typically takes 2-5 business days depending on your location and product availability.', 'كم تستغرق عملية التوصيل؟', 'يستغرق التوصيل عادة من 2 إلى 5 أيام عمل حسب موقعك وتوفر المنتج.', 'Shipping', 'الشحن', 5),
('Can I track my order?', 'Yes, once your order is shipped, you will receive tracking information via notification.', 'هل يمكنني تتبع طلبي؟', 'نعم، بمجرد شحن طلبك، ستتلقى معلومات التتبع عبر الإشعارات.', 'Orders', 'الطلبات', 6),
('What is your return policy?', 'We accept returns within 7 days of delivery for undamaged products. Please contact our support team.', 'ما هي سياسة الإرجاع الخاصة بكم؟', 'نقبل الإرجاع خلال 7 أيام من التوصيل للمنتجات غير التالفة. يرجى الاتصال بفريق الدعم.', 'Returns', 'الإرجاع', 7),
('Do you offer bulk pricing?', 'Yes, we offer competitive bulk pricing for large orders. Contact our sales team for a custom quote.', 'هل تقدمون أسعار الجملة؟', 'نعم، نقدم أسعار جملة تنافسية للطلبات الكبيرة. اتصل بفريق المبيعات للحصول على عرض سعر مخصص.', 'Pricing', 'الأسعار', 8),
('Where is Nama Steel located?', 'Our main office and warehouse are located in Saudi Arabia. Visit our Contact page for the exact address.', 'أين يقع مقر شركة نما للصلب؟', 'يقع مكتبنا الرئيسي ومستودعنا في المملكة العربية السعودية. زر صفحة الاتصال للحصول على العنوان الدقيق.', 'Company', 'الشركة', 9),
('What are your working hours?', 'We are open Sunday to Thursday, 8:00 AM to 5:00 PM.', 'ما هي ساعات العمل؟', 'نعمل من الأحد إلى الخميس، من الساعة 8:00 صباحاً حتى 5:00 مساءً.', 'Company', 'الشركة', 10),
('Do you provide installation services?', 'Yes, we offer professional installation services for structural steel products.', 'هل تقدمون خدمات التركيب؟', 'نعم، نقدم خدمات تركيب احترافية لمنتجات الصلب الهيكلي.', 'Services', 'الخدمات', 11),
('Can I get a custom quote?', 'Yes, you can request a custom quote through our website or by contacting our sales team directly.', 'هل يمكنني الحصول على عرض سعر مخصص؟', 'نعم، يمكنك طلب عرض سعر مخصص من خلال موقعنا أو بالاتصال بفريق المبيعات مباشرة.', 'Pricing', 'الأسعار', 12),
('What certifications does Nama Steel have?', 'We hold several quality certifications including ISO standards. Visit our Quality page for details.', 'ما هي الشهادات التي تمتلكها شركة نما للصلب؟', 'نمتلك العديد من شهادات الجودة بما في ذلك معايير ISO. زر صفحة الجودة للتفاصيل.', 'Quality', 'الجودة', 13),
('Do you ship internationally?', 'Currently, we primarily serve customers within Saudi Arabia. Contact us for international inquiries.', 'هل تشحنون دولياً؟', 'حالياً، نخدم العملاء بشكل رئيسي داخل المملكة العربية السعودية. اتصل بنا للاستفسارات الدولية.', 'Shipping', 'الشحن', 14),
('How do I contact customer support?', 'You can reach us via WhatsApp, phone, email, or through the contact form on our website.', 'كيف أتواصل مع خدمة العملاء؟', 'يمكنك التواصل معنا عبر واتساب أو الهاتف أو البريد الإلكتروني أو من خلال نموذج الاتصال على موقعنا.', 'Support', 'الدعم', 15),
('What steel grades do you offer?', 'We offer various steel grades suitable for construction, manufacturing, and industrial applications.', 'ما هي درجات الصلب التي تقدمونها؟', 'نقدم درجات متنوعة من الصلب المناسبة للبناء والتصنيع والتطبيقات الصناعية.', 'Products', 'المنتجات', 16),
('Can I visit your showroom?', 'Yes, you are welcome to visit our showroom during working hours. Please call ahead to schedule.', 'هل يمكنني زيارة معرضكم؟', 'نعم، نرحب بزيارتكم لمعرضنا خلال ساعات العمل. يرجى الاتصال مسبقاً لتحديد موعد.', 'Company', 'الشركة', 17),
('Do you offer warranty on products?', 'Yes, our products come with manufacturer warranty. Terms vary by product type.', 'هل تقدمون ضماناً على المنتجات؟', 'نعم، منتجاتنا تأتي مع ضمان المصنع. تختلف الشروط حسب نوع المنتج.', 'Products', 'المنتجات', 18),
('What is the minimum order quantity?', 'Minimum order quantities vary by product. Check individual product pages or contact us for details.', 'ما هو الحد الأدنى لكمية الطلب؟', 'يختلف الحد الأدنى لكمية الطلب حسب المنتج. تحقق من صفحات المنتجات أو اتصل بنا للتفاصيل.', 'Orders', 'الطلبات', 19),
('How can I become a partner?', 'Visit our Partners page or contact our business development team to discuss partnership opportunities.', 'كيف يمكنني أن أصبح شريكاً؟', 'زر صفحة الشركاء أو اتصل بفريق تطوير الأعمال لمناقشة فرص الشراكة.', 'Company', 'الشركة', 20),
('Do you offer financing options?', 'We offer flexible payment terms for qualified business customers. Contact sales for details.', 'هل تقدمون خيارات تمويل؟', 'نقدم شروط دفع مرنة للعملاء التجاريين المؤهلين. اتصل بالمبيعات للتفاصيل.', 'Payment', 'الدفع', 21),
('What is the shipping cost?', 'Shipping costs depend on your location and order size. You can see the exact cost at checkout.', 'ما هي تكلفة الشحن؟', 'تعتمد تكاليف الشحن على موقعك وحجم الطلب. يمكنك رؤية التكلفة الدقيقة عند الدفع.', 'Shipping', 'الشحن', 22),
('Can I cancel my order?', 'Orders can be cancelled before they are shipped. Contact us as soon as possible for cancellation.', 'هل يمكنني إلغاء طلبي؟', 'يمكن إلغاء الطلبات قبل شحنها. اتصل بنا في أقرب وقت ممكن للإلغاء.', 'Orders', 'الطلبات', 23),
('Do you provide technical specifications?', 'Yes, detailed technical specifications are available on each product page.', 'هل تقدمون المواصفات الفنية؟', 'نعم، المواصفات الفنية التفصيلية متاحة في صفحة كل منتج.', 'Products', 'المنتجات', 24),
('What sizes of steel do you carry?', 'We carry a wide range of sizes. Visit our products page for the full catalog.', 'ما هي أحجام الصلب المتوفرة لديكم؟', 'لدينا مجموعة واسعة من الأحجام. زر صفحة المنتجات للاطلاع على الكتالوج الكامل.', 'Products', 'المنتجات', 25),
('How do I create an account?', 'Click the Sign Up button on our website and fill in your details to create an account.', 'كيف أنشئ حساباً؟', 'انقر على زر التسجيل في موقعنا واملأ بياناتك لإنشاء حساب.', 'Account', 'الحساب', 26),
('Can I modify my order after placing it?', 'Order modifications may be possible before shipping. Contact support immediately.', 'هل يمكنني تعديل طلبي بعد تقديمه؟', 'قد يكون تعديل الطلب ممكناً قبل الشحن. اتصل بالدعم فوراً.', 'Orders', 'الطلبات', 27),
('What is your quality assurance process?', 'All our products undergo rigorous quality testing and comply with international standards.', 'ما هي عملية ضمان الجودة لديكم؟', 'تخضع جميع منتجاتنا لاختبارات جودة صارمة وتتوافق مع المعايير الدولية.', 'Quality', 'الجودة', 28),
('Do you offer discounts?', 'We regularly offer special promotions and discounts. Check our Offers page for current deals.', 'هل تقدمون خصومات؟', 'نقدم بانتظام عروضاً ترويجية وخصومات خاصة. تحقق من صفحة العروض للصفقات الحالية.', 'Pricing', 'الأسعار', 29),
('How do I reset my password?', 'Click "Forgot Password" on the login page and follow the instructions sent to your email.', 'كيف أعيد تعيين كلمة المرور؟', 'انقر على "نسيت كلمة المرور" في صفحة تسجيل الدخول واتبع التعليمات المرسلة إلى بريدك الإلكتروني.', 'Account', 'الحساب', 30),
('What types of steel sheets do you have?', 'We offer hot-rolled, cold-rolled, galvanized, and stainless steel sheets in various thicknesses.', 'ما أنواع ألواح الصلب المتوفرة لديكم؟', 'نقدم ألواح صلب مدلفنة على الساخن والبارد ومجلفنة وألواح من الفولاذ المقاوم للصدأ بسماكات مختلفة.', 'Products', 'المنتجات', 31),
('Do you sell steel pipes?', 'Yes, we offer various types of steel pipes including seamless and welded pipes in multiple sizes.', 'هل تبيعون أنابيب الصلب؟', 'نعم، نقدم أنواعاً مختلفة من أنابيب الصلب بما في ذلك الأنابيب السلسة والملحومة بأحجام متعددة.', 'Products', 'المنتجات', 32),
('What is your exchange policy?', 'We offer exchanges within 7 days for products in original condition. Contact support to arrange.', 'ما هي سياسة الاستبدال؟', 'نقدم استبدالاً خلال 7 أيام للمنتجات في حالتها الأصلية. اتصل بالدعم للترتيب.', 'Returns', 'الإرجاع', 33),
('Can I get a sample before ordering?', 'Yes, samples can be arranged for certain products. Contact our sales team.', 'هل يمكنني الحصول على عينة قبل الطلب؟', 'نعم، يمكن ترتيب عينات لمنتجات معينة. اتصل بفريق المبيعات.', 'Products', 'المنتجات', 34),
('Do you have a mobile app?', 'Our website is fully mobile-responsive and can be installed as a PWA on your device.', 'هل لديكم تطبيق جوال؟', 'موقعنا متجاوب بالكامل مع الجوال ويمكن تثبيته كتطبيق PWA على جهازك.', 'Support', 'الدعم', 35),
('What is VAT included in prices?', 'All prices on our website include 15% VAT as per Saudi regulations.', 'هل ضريبة القيمة المضافة مشمولة في الأسعار؟', 'جميع الأسعار على موقعنا تشمل ضريبة القيمة المضافة 15% وفقاً للأنظمة السعودية.', 'Pricing', 'الأسعار', 36),
('How can I get an invoice?', 'Invoices are automatically generated for all orders and can be downloaded from your order confirmation page.', 'كيف يمكنني الحصول على فاتورة؟', 'يتم إنشاء الفواتير تلقائياً لجميع الطلبات ويمكن تنزيلها من صفحة تأكيد الطلب.', 'Orders', 'الطلبات', 37),
('Do you offer cutting services?', 'Yes, we offer custom cutting services for steel products to meet your specifications.', 'هل تقدمون خدمات القطع؟', 'نعم، نقدم خدمات قطع مخصصة لمنتجات الصلب لتلبية مواصفاتكم.', 'Services', 'الخدمات', 38),
('What is rebar and do you sell it?', 'Rebar (reinforcing bar) is steel bar used in concrete construction. Yes, we offer various sizes.', 'ما هو حديد التسليح وهل تبيعونه؟', 'حديد التسليح هو قضبان فولاذية تستخدم في البناء الخرساني. نعم، نقدم أحجاماً مختلفة.', 'Products', 'المنتجات', 39),
('Can I schedule delivery at a specific time?', 'We can accommodate delivery scheduling for most locations. Please specify during checkout.', 'هل يمكنني جدولة التوصيل في وقت محدد؟', 'يمكننا تلبية جدولة التوصيل لمعظم المواقع. يرجى التحديد عند الدفع.', 'Shipping', 'الشحن', 40),
('What is the difference between hot-rolled and cold-rolled steel?', 'Hot-rolled steel is processed at high temperatures, while cold-rolled steel is processed at room temperature for a smoother finish.', 'ما الفرق بين الصلب المدلفن على الساخن والبارد؟', 'يتم معالجة الصلب المدلفن على الساخن في درجات حرارة عالية، بينما يتم معالجة المدلفن على البارد في درجة حرارة الغرفة للحصول على تشطيب أكثر نعومة.', 'Products', 'المنتجات', 41),
('Do you offer project consultations?', 'Yes, our engineering team can provide consultations for your steel construction projects.', 'هل تقدمون استشارات للمشاريع؟', 'نعم، يمكن لفريقنا الهندسي تقديم استشارات لمشاريع البناء الفولاذية الخاصة بكم.', 'Services', 'الخدمات', 42),
('How do I report a damaged product?', 'Contact our support team within 48 hours of delivery with photos of the damage for a quick resolution.', 'كيف أبلغ عن منتج تالف؟', 'اتصل بفريق الدعم خلال 48 ساعة من التوصيل مع صور للتلف للحصول على حل سريع.', 'Returns', 'الإرجاع', 43),
('What are structural steel beams?', 'Structural steel beams are load-bearing elements used in building construction. We offer I-beams, H-beams, and more.', 'ما هي العوارض الفولاذية الهيكلية؟', 'العوارض الفولاذية الهيكلية هي عناصر حاملة للأحمال تستخدم في البناء. نقدم عوارض I و H وغيرها.', 'Products', 'المنتجات', 44),
('Is same-day delivery available?', 'Same-day delivery may be available for select areas and products. Contact us for availability.', 'هل التوصيل في نفس اليوم متاح؟', 'قد يكون التوصيل في نفس اليوم متاحاً لمناطق ومنتجات محددة. اتصل بنا للتوفر.', 'Shipping', 'الشحن', 45),
('Do you provide material test certificates?', 'Yes, we provide mill test certificates (MTC) for our steel products upon request.', 'هل تقدمون شهادات اختبار المواد؟', 'نعم، نقدم شهادات اختبار المصنع (MTC) لمنتجاتنا الفولاذية عند الطلب.', 'Quality', 'الجودة', 46),
('What is galvanized steel?', 'Galvanized steel is steel coated with zinc to prevent rust and corrosion. We offer various galvanized products.', 'ما هو الصلب المجلفن؟', 'الصلب المجلفن هو صلب مطلي بالزنك لمنع الصدأ والتآكل. نقدم منتجات مجلفنة متنوعة.', 'Products', 'المنتجات', 47),
('How do I update my account information?', 'Log in to your account and visit the Profile page to update your personal information.', 'كيف أحدث معلومات حسابي؟', 'سجل الدخول إلى حسابك وزر صفحة الملف الشخصي لتحديث معلوماتك الشخصية.', 'Account', 'الحساب', 48),
('Do you sell stainless steel?', 'Yes, we offer a range of stainless steel products including sheets, bars, and pipes.', 'هل تبيعون الفولاذ المقاوم للصدأ؟', 'نعم، نقدم مجموعة من منتجات الفولاذ المقاوم للصدأ بما في ذلك الألواح والقضبان والأنابيب.', 'Products', 'المنتجات', 49),
('What are your steel bar specifications?', 'Our steel bars come in various diameters and grades. Check product details for specific specifications.', 'ما هي مواصفات قضبان الصلب لديكم؟', 'تأتي قضبان الصلب لدينا بأقطار ودرجات مختلفة. تحقق من تفاصيل المنتج للمواصفات المحددة.', 'Products', 'المنتجات', 50),
('Can I add items to an existing order?', 'Adding items to existing orders is not possible. Please place a new order for additional items.', 'هل يمكنني إضافة عناصر لطلب قائم؟', 'لا يمكن إضافة عناصر لطلبات قائمة. يرجى تقديم طلب جديد للعناصر الإضافية.', 'Orders', 'الطلبات', 51),
('Do you offer welding services?', 'Yes, we provide professional welding and fabrication services for custom steel structures.', 'هل تقدمون خدمات اللحام؟', 'نعم، نقدم خدمات لحام وتصنيع احترافية للهياكل الفولاذية المخصصة.', 'Services', 'الخدمات', 52),
('What is your company history?', 'Visit our About page to learn about Nama Steel history, mission, and values.', 'ما هو تاريخ شركتكم؟', 'زر صفحة من نحن للتعرف على تاريخ شركة نما للصلب ورسالتها وقيمها.', 'Company', 'الشركة', 53),
('How are prices calculated for bulk orders?', 'Bulk pricing is calculated based on quantity, product type, and delivery location. Request a quote for details.', 'كيف يتم حساب أسعار طلبات الجملة؟', 'يتم حساب أسعار الجملة بناءً على الكمية ونوع المنتج وموقع التوصيل. اطلب عرض سعر للتفاصيل.', 'Pricing', 'الأسعار', 54),
('Do you have a loyalty program?', 'We value our repeat customers and offer special pricing. Contact sales for loyalty benefits.', 'هل لديكم برنامج ولاء؟', 'نقدر عملاءنا الدائمين ونقدم أسعاراً خاصة. اتصل بالمبيعات لمعرفة مزايا الولاء.', 'Pricing', 'الأسعار', 55),
('Can I use the wishlist feature?', 'Yes, click the heart icon on any product to add it to your wishlist for future reference.', 'هل يمكنني استخدام ميزة قائمة الأمنيات؟', 'نعم، انقر على أيقونة القلب في أي منتج لإضافته إلى قائمة أمنياتك للرجوع إليه مستقبلاً.', 'Account', 'الحساب', 56),
('What are your delivery charges?', 'Delivery charges are based on your district and are shown at checkout. Some areas may have free delivery.', 'ما هي رسوم التوصيل؟', 'تعتمد رسوم التوصيل على حيك ويتم عرضها عند الدفع. قد تكون بعض المناطق مجانية التوصيل.', 'Shipping', 'الشحن', 57),
('Do you provide after-sales support?', 'Yes, our customer support team is available to assist you with any post-purchase questions.', 'هل تقدمون دعم ما بعد البيع؟', 'نعم، فريق دعم العملاء متاح لمساعدتكم في أي استفسارات بعد الشراء.', 'Support', 'الدعم', 58),
('How is steel priced?', 'Steel prices depend on market rates, grade, quantity, and specifications. Our prices are updated regularly.', 'كيف يتم تسعير الصلب؟', 'تعتمد أسعار الصلب على أسعار السوق والدرجة والكمية والمواصفات. يتم تحديث أسعارنا بانتظام.', 'Pricing', 'الأسعار', 59),
('Do you sell angle iron?', 'Yes, we carry a full range of angle iron in various sizes and thicknesses.', 'هل تبيعون الزوايا الحديدية؟', 'نعم، لدينا مجموعة كاملة من الزوايا الحديدية بأحجام وسماكات مختلفة.', 'Products', 'المنتجات', 60),
('What is the order confirmation process?', 'After placing an order, you receive a confirmation page with your order details and order number.', 'ما هي عملية تأكيد الطلب؟', 'بعد تقديم الطلب، تتلقى صفحة تأكيد بتفاصيل طلبك ورقم الطلب.', 'Orders', 'الطلبات', 61),
('Are your products SASO certified?', 'Yes, our products comply with SASO (Saudi Standards, Metrology and Quality Organization) requirements.', 'هل منتجاتكم معتمدة من ساسو؟', 'نعم، تتوافق منتجاتنا مع متطلبات الهيئة السعودية للمواصفات والمقاييس والجودة (ساسو).', 'Quality', 'الجودة', 62),
('Can I view my order history?', 'Yes, log in to your account to view your complete order history and track current orders.', 'هل يمكنني عرض سجل طلباتي؟', 'نعم، سجل الدخول إلى حسابك لعرض سجل طلباتك الكامل وتتبع الطلبات الحالية.', 'Account', 'الحساب', 63),
('Do you sell channel steel?', 'Yes, we offer C-channels and U-channels in various sizes for structural applications.', 'هل تبيعون الحديد المجرى؟', 'نعم، نقدم قنوات C و U بأحجام مختلفة للتطبيقات الهيكلية.', 'Products', 'المنتجات', 64),
('What is the weight limit for deliveries?', 'We can handle deliveries of any weight with appropriate transportation. Contact us for heavy loads.', 'ما هو الحد الأقصى لوزن التوصيل؟', 'يمكننا التعامل مع التوصيلات بأي وزن مع وسائل نقل مناسبة. اتصل بنا للأحمال الثقيلة.', 'Shipping', 'الشحن', 65),
('Do you offer crane/unloading services?', 'Crane and unloading services can be arranged for an additional fee. Specify during checkout.', 'هل تقدمون خدمات رافعة/تفريغ؟', 'يمكن ترتيب خدمات الرافعة والتفريغ برسوم إضافية. حدد ذلك عند الدفع.', 'Services', 'الخدمات', 66),
('How do I apply to be a marketer?', 'Visit our website and fill out the marketer application form with your details and experience.', 'كيف أتقدم لأكون مسوقاً؟', 'زر موقعنا واملأ نموذج طلب المسوق بتفاصيلك وخبراتك.', 'Company', 'الشركة', 67),
('What steel products are best for construction?', 'For construction, we recommend rebar, structural beams, steel sheets, and welded mesh.', 'ما هي أفضل منتجات الصلب للبناء؟', 'للبناء، ننصح بحديد التسليح والعوارض الهيكلية وألواح الصلب والشبك الملحوم.', 'Products', 'المنتجات', 68),
('Can I pay with multiple payment methods?', 'Currently, each order can use one payment method. Contact us for special arrangements.', 'هل يمكنني الدفع بعدة طرق دفع؟', 'حالياً، يمكن لكل طلب استخدام طريقة دفع واحدة. اتصل بنا لترتيبات خاصة.', 'Payment', 'الدفع', 69),
('Do you have flat bars?', 'Yes, we stock flat bars in various widths, thicknesses, and lengths.', 'هل لديكم قضبان مسطحة؟', 'نعم، لدينا قضبان مسطحة بعروض وسماكات وأطوال مختلفة.', 'Products', 'المنتجات', 70),
('How do I leave a review?', 'Visit our About page and use the review form to share your experience with Nama Steel.', 'كيف أترك تقييماً؟', 'زر صفحة من نحن واستخدم نموذج التقييم لمشاركة تجربتك مع شركة نما للصلب.', 'Support', 'الدعم', 71),
('What is the standard length of steel bars?', 'Standard steel bars are typically 6m or 12m long. Custom lengths may be available upon request.', 'ما هو الطول القياسي لقضبان الصلب؟', 'قضبان الصلب القياسية عادة بطول 6 متر أو 12 متر. قد تتوفر أطوال مخصصة عند الطلب.', 'Products', 'المنتجات', 72),
('Can I get a tax invoice?', 'Yes, all orders include a tax invoice with VAT details as per Saudi tax regulations.', 'هل يمكنني الحصول على فاتورة ضريبية؟', 'نعم، جميع الطلبات تتضمن فاتورة ضريبية مع تفاصيل ضريبة القيمة المضافة وفقاً للأنظمة الضريبية السعودية.', 'Orders', 'الطلبات', 73),
('Do you offer painted steel?', 'Yes, we offer pre-painted and powder-coated steel products in various colors.', 'هل تقدمون صلباً مطلياً؟', 'نعم، نقدم منتجات صلب مطلية مسبقاً ومطلية بالمسحوق بألوان متنوعة.', 'Products', 'المنتجات', 74),
('How can I subscribe to newsletters?', 'Sign up on our website to receive updates about new products, offers, and industry news.', 'كيف يمكنني الاشتراك في النشرة الإخبارية؟', 'سجل في موقعنا لتلقي تحديثات حول المنتجات الجديدة والعروض وأخبار الصناعة.', 'Support', 'الدعم', 75),
('What is the maximum order size?', 'There is no maximum order size. We can handle orders of any scale with proper logistics.', 'ما هو الحد الأقصى لحجم الطلب؟', 'لا يوجد حد أقصى لحجم الطلب. يمكننا التعامل مع طلبات بأي حجم مع لوجستيات مناسبة.', 'Orders', 'الطلبات', 76),
('Do you offer bending services?', 'Yes, we provide steel bending and shaping services according to your project requirements.', 'هل تقدمون خدمات الثني؟', 'نعم، نقدم خدمات ثني وتشكيل الصلب وفقاً لمتطلبات مشروعكم.', 'Services', 'الخدمات', 77),
('What is steel mesh used for?', 'Steel mesh is used for concrete reinforcement, fencing, and industrial applications.', 'ما هو استخدام الشبك الفولاذي؟', 'يستخدم الشبك الفولاذي لتقوية الخرسانة والتسييج والتطبيقات الصناعية.', 'Products', 'المنتجات', 78),
('How do I check product availability?', 'Product availability is shown on each product page. You can also contact us for real-time stock info.', 'كيف أتحقق من توفر المنتج؟', 'يظهر توفر المنتج في صفحة كل منتج. يمكنك أيضاً الاتصال بنا لمعرفة المخزون الفعلي.', 'Products', 'المنتجات', 79),
('Do you deliver on weekends?', 'Standard deliveries are made Sunday through Thursday. Weekend delivery may be arranged upon request.', 'هل تقومون بالتوصيل في عطلة نهاية الأسبوع؟', 'يتم التوصيل القياسي من الأحد إلى الخميس. يمكن ترتيب التوصيل في عطلة نهاية الأسبوع عند الطلب.', 'Shipping', 'الشحن', 80),
('What are hollow sections?', 'Hollow sections are tubular steel profiles (square, rectangular, circular) used in construction and fabrication.', 'ما هي المقاطع المجوفة؟', 'المقاطع المجوفة هي مقاطع أنبوبية من الصلب (مربعة، مستطيلة، دائرية) تستخدم في البناء والتصنيع.', 'Products', 'المنتجات', 81),
('Can I request a callback?', 'Yes, contact us through the website and request a callback. Our team will reach out promptly.', 'هل يمكنني طلب اتصال عودة؟', 'نعم، تواصل معنا عبر الموقع واطلب اتصال عودة. سيتواصل فريقنا معك بسرعة.', 'Support', 'الدعم', 82),
('Do you provide engineering drawings?', 'Yes, we can provide engineering drawings and technical documentation for custom orders.', 'هل تقدمون رسومات هندسية؟', 'نعم، يمكننا تقديم رسومات هندسية ووثائق فنية للطلبات المخصصة.', 'Services', 'الخدمات', 83),
('What is the difference between mild and high-tensile steel?', 'Mild steel has lower carbon content and is more ductile, while high-tensile steel is stronger but less flexible.', 'ما الفرق بين الصلب اللين والصلب عالي الشد؟', 'الصلب اللين يحتوي على نسبة كربون أقل وأكثر ليونة، بينما الصلب عالي الشد أقوى لكنه أقل مرونة.', 'Products', 'المنتجات', 84),
('Do you offer annual contracts?', 'Yes, we offer annual supply contracts with fixed pricing for qualified customers.', 'هل تقدمون عقوداً سنوية؟', 'نعم، نقدم عقود توريد سنوية بأسعار ثابتة للعملاء المؤهلين.', 'Pricing', 'الأسعار', 85),
('How is steel stored to prevent corrosion?', 'We store all products in covered warehouses with proper ventilation to prevent corrosion.', 'كيف يتم تخزين الصلب لمنع التآكل؟', 'نخزن جميع المنتجات في مستودعات مغطاة بتهوية مناسبة لمنع التآكل.', 'Quality', 'الجودة', 86),
('Can I arrange pickup instead of delivery?', 'Yes, you can pick up your order from our warehouse. Select pickup option during checkout.', 'هل يمكنني ترتيب الاستلام بدلاً من التوصيل؟', 'نعم، يمكنك استلام طلبك من مستودعنا. اختر خيار الاستلام عند الدفع.', 'Shipping', 'الشحن', 87),
('What is your environmental policy?', 'We are committed to sustainable practices and responsible sourcing of steel materials.', 'ما هي سياستكم البيئية؟', 'نلتزم بالممارسات المستدامة والمصادر المسؤولة لمواد الصلب.', 'Company', 'الشركة', 88),
('Do you sell wire products?', 'Yes, we offer various wire products including binding wire, mesh wire, and barbed wire.', 'هل تبيعون منتجات الأسلاك؟', 'نعم، نقدم منتجات أسلاك متنوعة بما في ذلك أسلاك الربط وأسلاك الشبك والأسلاك الشائكة.', 'Products', 'المنتجات', 89),
('How do I report a billing issue?', 'Contact our finance department via email or phone with your order number for billing inquiries.', 'كيف أبلغ عن مشكلة في الفوترة؟', 'اتصل بقسم المالية عبر البريد الإلكتروني أو الهاتف مع رقم طلبك لاستفسارات الفوترة.', 'Payment', 'الدفع', 90),
('Do you provide steel for oil and gas industry?', 'Yes, we supply specialized steel products for oil and gas applications meeting industry standards.', 'هل تقدمون صلباً لصناعة النفط والغاز؟', 'نعم، نورد منتجات صلب متخصصة لتطبيقات النفط والغاز تلبي معايير الصناعة.', 'Products', 'المنتجات', 91),
('What is checkered plate?', 'Checkered plate (also called diamond plate) is a steel sheet with raised patterns for anti-slip purposes.', 'ما هو اللوح المنقوش؟', 'اللوح المنقوش (يسمى أيضاً لوح الماس) هو لوح صلب بنقوش بارزة لأغراض منع الانزلاق.', 'Products', 'المنتجات', 92),
('Can I get credit terms?', 'Credit terms are available for approved business accounts. Apply through our sales department.', 'هل يمكنني الحصول على شروط ائتمان؟', 'شروط الائتمان متاحة لحسابات الأعمال المعتمدة. تقدم من خلال قسم المبيعات.', 'Payment', 'الدفع', 93),
('Do you sell roofing sheets?', 'Yes, we offer corrugated and flat roofing sheets in various materials and colors.', 'هل تبيعون ألواح التسقيف؟', 'نعم، نقدم ألواح تسقيف مموجة ومسطحة بمواد وألوان متنوعة.', 'Products', 'المنتجات', 94),
('How can I provide feedback?', 'You can provide feedback through our contact form, email, or by leaving a review on our website.', 'كيف يمكنني تقديم ملاحظات؟', 'يمكنك تقديم ملاحظات من خلال نموذج الاتصال أو البريد الإلكتروني أو بترك تقييم على موقعنا.', 'Support', 'الدعم', 95),
('What safety equipment do you recommend?', 'When handling steel, we recommend gloves, safety boots, hard hats, and proper lifting equipment.', 'ما معدات السلامة التي توصون بها؟', 'عند التعامل مع الصلب، ننصح بالقفازات وأحذية السلامة والخوذات ومعدات الرفع المناسبة.', 'Support', 'الدعم', 96),
('Do you sell square bars?', 'Yes, we stock square bars in various sizes from 10mm to 100mm.', 'هل تبيعون قضباناً مربعة؟', 'نعم، لدينا قضبان مربعة بأحجام مختلفة من 10 مم إلى 100 مم.', 'Products', 'المنتجات', 97),
('How are heavy orders delivered?', 'Heavy orders are delivered using flatbed trucks or trailers with proper loading equipment.', 'كيف يتم توصيل الطلبات الثقيلة؟', 'يتم توصيل الطلبات الثقيلة باستخدام شاحنات مسطحة أو مقطورات مع معدات تحميل مناسبة.', 'Shipping', 'الشحن', 98),
('What makes Nama Steel different?', 'We combine quality products, competitive pricing, fast delivery, and excellent customer service.', 'ما الذي يميز شركة نما للصلب؟', 'نجمع بين المنتجات عالية الجودة والأسعار التنافسية والتوصيل السريع وخدمة العملاء الممتازة.', 'Company', 'الشركة', 99),
('How do I share a product with someone?', 'Use the WhatsApp share button on any product page to share product details with others.', 'كيف أشارك منتجاً مع شخص آخر؟', 'استخدم زر مشاركة واتساب في أي صفحة منتج لمشاركة تفاصيل المنتج مع الآخرين.', 'Support', 'الدعم', 100);
